    >>> danger_corner([[0,0],[0,1],[1,1],[1,0]])
    0
    """
    counter = 0
    for i in range(len(points)):
        for j in range(i+1, len(points)):
            if (points[j][0] - points[i][0]) * (points[j][1] - points[i][1]) < 0:
