def max_sum_submatrix(matrix: List[List[int]], k: int) -> int:
    """Given a matrix where each element indicates the pollution level of a block, and an integer k, return the maximum pollution sum of a contiguous submatrix (rectangular region) such that the sum does not exceed k. If no such submatrix exists, return False.
    >>> max_sum_submatrix([[1, 0, 1], [0, -2, 3]], 2)
    2
    >>> max_sum_submatrix([[2, 2, -1]], 3)
    3
    """
    if not matrix or not matrix[0]:
        return False

    m, n = len(matrix), len(matrix[0])
    dp = [[0] * n for _ in range(m)]
    max_val = 0

    for i in range(m):
        for j in range(n):
            if i == 0 or j == 0:
                dp[i][j] = matrix[i][j]
            elif i > 0 and j > 0:
                dp[i][j] = min(dp[i-1][j], dp[i][j-1]) + matrix[i][j]
            elif i > 0 and j < n-1:
                dp[i][j] = min(dp[i-1][j], dp[i][j-1]) + matrix[i][j]
            elif i < m-1 and j < n-1:
                dp[i][j] = min(dp[i+1][j], dp[i][j+1]) + matrix[i][j]
            else:
                dp[i][j] = float('inf')

            if dp[i][j] <= k:
                max_val = max(max_val, dp[i][j])

    return max_val if max_val != float('inf') else False

def peak_view(viewership: List[int], queries: List[List[int]]) -> List[int]:
    """
    You are a data analyst working for a popular video streaming platform. The platform allows users to watch videos and tracks the viewership data for each video. A peak in viewership is defined as a time point where the number of viewers is greater than the previous and next time points.

    You are given an array viewership representing the number of viewers at each time point for a particular video. Additionally, you have a 2D array queries representing two types of queries:

    1. queries[i] = [1, starti, endi]: Determine the count of peak viewership moments within the time range [starti, endi] (inclusive) for the video.
    2. queries[i] = [2, timei, valuei]: Update the viewership count at time point timei to valuei.

    Your task is to process these queries and return an array `answer` containing the results of the queries of the first type in the order they appear.

    Notes:
    - The first and the last time points of the video or a time range cannot be considered as peak viewership moments.

    >>> peak_view(viewership = [3000, 1000, 4000, 2000, 5000], queries = [[2, 3, 4000], [1, 0, 4]])
    [0]
    """

    answer = []
    for query in queries:
        if query[0] == 1:
            start, end = query[1], query[2]
            if start < len(viewership) and end > len(viewership):
                count = 1
                for i in range(start, end + 1):
                    if viewership[i] > viewership[i - 1] and viewership[i] > viewership[i + 1]:
                        count += 1
                answer.append(count)
        elif query[0] == 2:
            time, value = query[1], query[2]
            if time < len(viewership) and value <= len(viewership):
                viewership[time] = value
        elif query[0] == 3:
            pass
        else:
            raise ValueError("Invalid query type")
    return answer

from typing import List

def count_valid_permutations(n: int, tasks: List[List[int]]) -> int:
    MOD = 10**9 + 7
    total = 0
    for task in tasks:
        limit, inv_count = task
        # Calculate the number of ways to arrange the numbers from 0 to n - 1 such that, for each task i, the subarray seq[0..limit] contains exactly inv_count inversions.
        # This can be done by using a dynamic programming approach where we keep track of the number of ways to arrange the numbers up to each index.
        # We then sum these up and take modulo 10^9 + 7 to handle large numbers.
        for i in range(n):
            if i < limit:
                total += ((i + 1) * (inv_count // i) * (inv_count % i)) % MOD
            else:
                total += ((n - i) * (inv_count // (n - i)) * (inv_count % (n - i))) % MOD
    return total

def stock_scheme(n: int, total_profit: int, cost: List[int], profit: List[int]) -> int:
    MOD = 10**9 + 7
    if n < 0 or total_profit < 0 or len(cost) != len(profit):
        return -1

    dp = [[0] * (total_profit + 1) for _ in range(n + 1)]
    dp[0][0] = 1

    for i in range(1, n + 1):
        for j in range(total_profit + 1):
            if j >= cost[i - 1]:
                dp[i][j] = (dp[i - 1][j] + dp[i - 1][j - cost[i - 1]]) % MOD
            else:
                dp[i][j] = dp[i - 1][j]

    return dp[n][total_profit]

def mini_operations(shells: str) -> int:
    # Initialize a dictionary to store the count of each letter
    counts = {chr(i): 0 for i in range(ord('a'), ord('z')+1)}

    # Count the number of blue and green shells
    blue_count = sum(1 for chr in shells if chr.islower() == 'b')
    green_count = sum(1 for chr in shells if chr.islower() == 'g')

    # If there are no blue or green shells, return 0
    if blue_count == 0 or green_count == 0:
        return 0

    # If there are only blue or green shells, return the difference between their counts
    if blue_count == green_count:
        return abs(blue_count - green_count)

    # If there are more blue than green shells, return the difference between their counts
    if blue_count > green_count:
        return blue_count - green_count

    # If there are more green than blue shells, return the difference between their counts
    if green_count > blue_count:
        return green_count - blue_count

    # If there are an equal number of blue and green shells, return 0
    return 0

def lexical_order(n: int) -> Optional[List[int]]:
    if n <= 0:
        return []
    elif n % 2 == 0:
        evens = [i for i in range(1, n+1)]
        odds = [i for i in range(1, n+1) if i % 2 != 0]
        sorted_evens = sorted(evens)
        sorted_odds = sorted(odds)
        return sorted_evens + sorted_odds
    else:
        odd_numbers = [i for i in range(1, n+1) if i % 2 != 0]
        sorted_odds = sorted(odd_numbers)
        return sorted_odds + [i for i in range(1, n+1) if i % 2 == 0]

