def generate_string_permutation(raw_data: List[str], replaced_str: str) -> int:
    """Generate all permutations of raw_data elements, excluding one element per permutation.
    Replace up to three occurrences of replaced_str in each permutation with an empty string.
    Return the number of unique strings.
    >>> generate_string_permutation(["a", "b", "c"], "a")
    4
    >>> generate_string_permutation(["hello", "world", "rock", "great"], "or")
    24
    """

    # Create a set to store unique strings
    unique_strings = set()

    # Generate all permutations of the input list
    for i in range(len(raw_data)):
        for j in range(i+1, len(raw_data)+1):
            for k in range(j+1, len(raw_data)+1):
                new_string = ""
                for l in range(k+1, len(raw_data)+1):
                    new_string += raw_data[i] + raw_data[j] + raw_data[k] + raw_data[l]
                if new_string != raw_data[i] and new_string != raw_data[j] and new_string != raw_data[k]:
                    unique_strings.add(new_string)

    return len(unique_strings)

def string_count(s: str, queries: List[List[int]]) -> List[int]:
    ans = []
    for query in queries:
        li, ri = query
        if li == 0 or ri == len(s):
            ans.append(0)
            continue
        substr = s[li:ri]
        if substr[0] == substr[-1]:
            ans.append(len(substr))
        else:
            ans.append(0)
    return ans

