def jumping_map(arr: List[List[int]]) -> int:
    n = len(arr)
    if n == 0:
        return 0
    dp = [[0]*n for _ in range(n)]
    dp[0][0] = arr[0][0]
    for i in range(1, n):
        for j in range(i+1):
            if abs(arr[i][j] - arr[i-1][j]) <= dp[i][j-1]:
                dp[i][j] = min(dp[i-1][j], dp[i][j-1], arr[i][j]) + 1
            else:
                dp[i][j] = min(dp[i-1][j], dp[i][j-1])
    return dp[-1][-1]

