def get_min_flip_cost_to_match(s1: str, s2: str, x: int) -> int:
    n = len(s1)
    if n != len(s2):
        return -1

    dp = [[0]*(x+1) for _ in range(n+1)]
    for i in range(n+1):
        dp[i][0] = i

    for i in range(1, n+1):
        for j in range(1, min(i, x)+1):
            if s1[i-1] == s2[j-1]:
                dp[i][j] = dp[i-1][j-1]
            else:
                dp[i][j] = min(dp[i-1][j], dp[i][j-1]) + 1

    return dp[n][x]

def space_centered_text(text: str) -> str:
    # Split the text into words based on spaces
    words = text.split(' ')

    # Count the number of spaces in the text
    spaces = len(text.replace(" ", ""))

    # If there is only one word, append all spaces to the end of that word
    if len(words) == 1:
        return ' ' * spaces + words[0]

    # Otherwise, calculate the number of spaces between words as floor(spaces / (words - 1))
    spaces_between_words = spaces // (len(words) - 1)

    # Reconstruct the string by alternating words and spaces between words
    result = []
    for i in range(len(words)):
        if i < spaces_between_words:
            result.append(words[i])
        else:
            result.append(' ' * spaces_between_words + words[i])

    # Append any extra spaces to the end
    result.append(' ' * (len(words) - len(result)) + ''.join(result))

    return ''.join(result)

