    visited = {}

    # Define the possible moves Jack can make
    moves = [(0, 1), (0, -1), (1, 0), (-1, 0)]

    # Helper function to check if a word exists in the grid
    def check_word(grid, target):
        for i in range(len(grid)):
            for j in range(len(grid[i])):
                if grid[i][j] == target:
                    return True
        return False

    # Check if the target word exists in the grid
    if check_word(grid, target):
        return True

    # If the target word does not exist, try all possible words starting from the first cell
