                            if check_word(grid, word):
                                return True
                            del visited[(new_i, new_j)]
    return False

def compress_string(s: List[str]) -> List[int]:
    compressed = s[0]
    for i in range(1, len(s)):
        if s[i] != s[i-1][:len(s[i-1])]:
            compressed += s[i]
    return [i for i in range(len(s)) if s[i] == compressed]

def stock_scheme(n: int, total_profit: int, cost: List[int], profit: List[int]) -> int:
    MOD = 10**9 + 7
    if n < 0 or total_profit < 0 or len(cost) != len(profit):
        return -1

    dp = [[0] * (total_profit + 1) for _ in range(n + 1)]
    dp[0][0] = 1

    for i in range(1, n + 1):
        for j in range(total_profit + 1):
            if j >= cost[i - 1]:
                dp[i][j] = (dp[i - 1][j] + dp[i - 1][j - cost[i - 1]]) % MOD
            else:
                dp[i][j] = dp[i - 1][j]

    return dp[n][total_profit]

def mini_operations(shells: str) -> int:
    # Initialize a dictionary to store the count of each letter
    counts = {chr(i): 0 for i in range(97, 123)}
    for char in shells:
        if char.islower():
            counts[char] += 1
    # Initialize a variable to keep track of the number of switches
    switches = 0
    # Iterate over the dictionary and perform operations
    for key in counts:
        # If the count of a letter is odd, swap it with another letter
        if counts[key] % 2 != 0:
            char = chr(ord('a') + key % 26)
            counts[char] -= 1
            counts[key] += 1
            switches += 1
    return switches

