import math

def euclidean_distance(point1, point2):
    return math.sqrt((point1[0] - point2[0])**2 + (point1[1] - point2[1])**2 + (point1[2] - point2[2])**2)

def k_closest(points: List[List[int]], target_point:List[int], k: int) -> List[int]:
    points.sort(key=lambda x: (-euclidean_distance(x, target_point), x[0], x[1], x[2]))
    return points[:k]
